VALUES
  ('promotion-d592fc58-moex-00018', 'promotion-d592fc58', 'promotion-d592fc58-moex-114-9b7ab1bb', 'sub-promotion-d592fc58-02', NULL, 'single_choice', '17歲之甲，對乙有新臺幣（下同）1,000元之債權，而乙對甲有1,200元之債權，雙方之債務均屆 清償期，甲未得其法定代理人事先允許，向乙表示抵銷。下列敘述何者正確？', '["甲與乙之債權債務關係，於1,000元範圍內消滅", "甲與乙之債權債務關係，因甲抵銷而全部消滅", "甲與乙之債權債務關係，於甲成年後，始消滅", "甲與乙之債權債務關係，並不因甲抵銷而消滅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00019', 'promotion-d592fc58', 'promotion-d592fc58-moex-114-9b7ab1bb', 'sub-promotion-d592fc58-02', NULL, 'single_choice', '就甲、乙、丙三人對丁負有連帶債務之情形，下列敘述何者正確？', '["甲向丁表示承認連帶債務存在時，其中斷時效之效力及於乙、丙", "甲對丁給付遲延，其效力亦及於乙、丙", "甲向丁為超過其分擔部分之清償後，甲即脫離連帶債務關係", "甲向丁提起確認連帶債務不存在之訴，而獲勝訴確定判決時，該判決效力及於乙、丙"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00020', 'promotion-d592fc58', 'promotion-d592fc58-moex-114-9b7ab1bb', 'sub-promotion-d592fc58-02', NULL, 'single_choice', '下列關於不動產物權登記效力之敘述，何者正確？', '["甲訴請乙履行不動產所有權移轉登記之判決勝訴確定後，依民法第758條有關設權登記規定， 須向地政機關辦理登記完畢，始取得其所有權", "甲將不動產所有權移轉登記予乙，嗣後，甲以該移轉行為係無效，而訴請乙塗銷登記時，乙得 適用登記之推定力而主張自己為所有人", "以所有之意思，占有無主之土地，係非因法律行為而取得不動產物權，不待登記即取得所有權", "不動產共有人間關於共有物之分管約定，係依法律行為而使不動產物權發生變更，非經登記， 不生效力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00021', 'promotion-d592fc58', 'promotion-d592fc58-moex-114-9b7ab1bb', 'sub-promotion-d592fc58-02', NULL, 'single_choice', '甲、乙訂立買賣甲所有電腦之契約時，因甲仍暫時有使用該電腦之需求，乙同意將該電腦貸予甲 繼續使用一段期間。該電腦之所有人為何？', '["甲所有", "乙所有", "甲、乙分別共有", "甲、乙公同共有"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00022', 'promotion-d592fc58', 'promotion-d592fc58-moex-114-9b7ab1bb', 'sub-promotion-d592fc58-02', NULL, 'single_choice', '就甲於乙所有之A地設定登記普通地上權後，A地遭丙侵奪之情形，下列敘述何者正確？', '["乙得僅將其對丙之所有物返還請求權讓與第三人", "甲得直接請求丙將受侵奪之A地返還於己", "乙對丙之所有物返還請求權，經15年不行使而消滅", "甲不得對善意無過失之丙請求返還A地於己"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00023', 'promotion-d592fc58', 'promotion-d592fc58-moex-114-9b7ab1bb', 'sub-promotion-d592fc58-02', NULL, 'single_choice', '為擔保甲對乙之新臺幣（下同）1,000萬元X債權，乙、丙、丁分別提供其各自所有之A、B、C 不動產供甲設定均為第一次序之普通抵押權，其中C設定擔保金額為500萬元。X債權清償期屆 至時，乙無力清償，甲乃實行對上述不動產之抵押權，A、B、C分別拍賣，得款400萬元、500 萬元、300萬元。就各自拍賣所得金額，應如何進行分配（小數點部分四捨五入）？', '["A分配333萬元、B分配417萬元、C分配250萬元", "A分配400萬元、B分配300萬元、C分配300萬元", "A分配400萬元、B分配375萬元、C分配225萬元", "A分配311萬元、B分配389萬元、C分配300萬元 13540 13740"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00024', 'promotion-d592fc58', 'promotion-d592fc58-moex-114-9b7ab1bb', 'sub-promotion-d592fc58-02', NULL, 'single_choice', '下列關於分別共有物處分之敘述，何者錯誤？', '["分別共有之動產，各共有人得自由處分其應有部分", "分別共有之動產，對共有物之處分，應得共有人全體之同意", "分別共有之不動產，對共有物之處分，應得共有人全體之同意", "分別共有不動產之處分，除其應有部分合計超過三分之二，其人數不予計算者外，應以共有人 過半數及其應有部分合計過半數之同意為之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00025', 'promotion-d592fc58', 'promotion-d592fc58-moex-114-9b7ab1bb', 'sub-promotion-d592fc58-02', NULL, 'single_choice', '甲僅有一子乙，某日甲死亡，留有現金新臺幣（下同）500萬元，丙對甲有1,000萬元債權，當乙 作出下列何種行為時，仍得主張民法第1148條第2項規定之限定責任？', '["乙將該500萬元提領並私藏於朋友家", "乙於甲生前對甲恐嚇：不給錢，我就殺了你，甲聞後心生畏懼未予理會", "乙於甲死亡後向法院陳報遺產清冊，記載甲僅遺留現金50萬元", "乙與丙勾結製造對甲之假債權400萬元，並先對丙清償"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00026', 'promotion-d592fc58', 'promotion-d592fc58-moex-114-9b7ab1bb', 'sub-promotion-d592fc58-02', NULL, 'single_choice', '甲男乙女為夫妻，二人為某特定目的而通謀虛偽離婚，並辦理離婚登記。嗣後，於分居期間甲邂 逅丙女，丙信賴甲乙之離婚登記，而與甲結婚，並辦理結婚登記。下列敘述何者正確？', '["丙信賴甲乙之離婚登記，甲丙婚姻有效", "丙受甲詐欺而結婚，得撤銷其婚姻", "甲乙婚姻關係存在", "甲乙婚姻視為消滅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00027', 'promotion-d592fc58', 'promotion-d592fc58-moex-114-9b7ab1bb', 'sub-promotion-d592fc58-02', NULL, 'single_choice', '甲為乙男之非婚生子女，甲於乙死亡前，均無任何接觸。下列敘述何者正確？', '["乙以遺囑認領甲，甲不知，則不生認領效力", "乙以遺囑認領甲，並就遺贈附停止條件，條件成就前，不生認領效力", "甲於乙死亡後，得向乙之繼承人提起認領之訴", "甲其實曾寫信要求乙認領，乙於死亡前回信承諾，因不符遺囑要式之規定，不生認領效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL)
